158→// ===========================================================================
159→// 1. Workspace Overview (lightweight orientation, no params)
160→// ===========================================================================
161→
162→/** Build a lightweight workspace overview for agent orientation */
163→export async function buildWorkspaceOverview(input: {
164→  surreal: Surreal;
165→  workspaceRecord: RecordId<"workspace", string>;
166→  workspaceName: string;
167→  excludeSessionId?: string;
168→}): Promise<WorkspaceOverview> {
169→  const { surreal, workspaceRecord, workspaceName } = input;
170→
171→  const overviewQuery = `
172→    SELECT id, name, status, description
173→    FROM project
174→    WHERE id IN (SELECT VALUE out FROM has_project WHERE \`in\` = $workspace);
175→
176→    SELECT out AS project_id, record::tb(\`in\`) AS entity_type, count() AS count
177→    FROM belongs_to
178→    WHERE out IN (SELECT VALUE out FROM has_project WHERE \`in\` = $workspace)
179→    GROUP BY project_id, entity_type;
180→
181→    SELECT \`in\` AS project_id, count() AS count
182→    FROM has_feature
183→    WHERE \`in\` IN (SELECT VALUE out FROM has_project WHERE \`in\` = $workspace)
184→    GROUP BY project_id;
185→  `;
186→
187→  const [projectRows, entityCounts, featureCounts] = await surreal
188→    .query<[ProjectRow[], EntityCountRow[], FeatureCountRow[]]>(overviewQuery, {
189→      workspace: workspaceRecord,
190→    })
191→    .collect<[ProjectRow[], EntityCountRow[], FeatureCountRow[]]>();
192→
193→  const countsByProject = buildProjectCountMaps(entityCounts, featureCounts);
194→  const hotItems = await loadHotItems(surreal, workspaceRecord);
195→  const activeSessions = await loadActiveSessions(surreal, workspaceRecord, undefined, input.excludeSessionId);
196→
197→  return {
198→    workspace: { id: workspaceRecord.id as string, name: workspaceName },
199→    projects: projectRows.map((p) => ({
200→      id: toRawId(p.id),
201→      name: p.name,
202→      status: p.status,
203→      ...(p.description ? { description: p.description } : {}),
204→      counts: countsByProject.get(toRawId(p.id)) ?? { tasks: 0, decisions: 0, features: 0, questions: 0 },
205→    })),
206→    hot_items: hotItems,
207→    active_sessions: activeSessions,
208→  };
209→}
210→
211→function buildProjectCountMaps(
212→  entityCounts: EntityCountRow[],
213→  featureCounts: FeatureCountRow[],
214→): Map<string, { tasks: number; decisions: number; features: number; questions: number }> {
215→  const map = new Map<string, { tasks: number; decisions: number; features: number; questions: number }>();
216→
217→  for (const row of entityCounts) {
218→    const pid = toRawId(row.project_id);
219→    const entry = map.get(pid) ?? { tasks: 0, decisions: 0, features: 0, questions: 0 };
220→    if (row.entity_type === "task") entry.tasks = row.count;
221→    else if (row.entity_type === "decision") entry.decisions = row.count;
222→    else if (row.entity_type === "question") entry.questions = row.count;
223→    map.set(pid, entry);
224→  }
225→
226→  for (const row of featureCounts) {
227→    const pid = toRawId(row.project_id);
228→    const entry = map.get(pid) ?? { tasks: 0, decisions: 0, features: 0, questions: 0 };
229→    entry.features = row.count;
230→    map.set(pid, entry);
231→  }
232→
233→  return map;
234→}
