702→/** Load entities changed since a timestamp (project-scoped) */
703→async function loadRecentChanges(
704→  surreal: Surreal,
705→  workspaceRecord: RecordId<"workspace", string>,
706→  projectRecord: RecordId<"project", string>,
707→  since: string,
708→): Promise<RecentChangeContext[]> {
709→  const sinceDate = new Date(since);
710→
711→  const query = `
712→    LET $project_entity_ids = SELECT VALUE \`in\` FROM belongs_to WHERE out = $project;
713→
714→    LET $recent_decisions = SELECT "decision" AS entity_type, summary AS entity_name, status AS change_type, updated_at AS changed_at
715→    FROM decision
716→    WHERE workspace = $workspace AND id IN $project_entity_ids AND updated_at > $since
717→    ORDER BY updated_at DESC LIMIT 20;
718→
719→    LET $recent_tasks = SELECT "task" AS entity_type, title AS entity_name, status AS change_type, updated_at AS changed_at
720→    FROM task
721→    WHERE workspace = $workspace AND id IN $project_entity_ids AND updated_at > $since
722→    ORDER BY updated_at DESC LIMIT 20;
723→
724→    LET $recent_questions = SELECT "question" AS entity_type, text AS entity_name, status AS change_type, updated_at AS changed_at
725→    FROM question
726→    WHERE workspace = $workspace AND id IN $project_entity_ids AND updated_at > $since
727→    ORDER BY updated_at DESC LIMIT 20;
728→
729→    LET $recent_observations = SELECT "observation" AS entity_type, text AS entity_name, severity AS change_type, updated_at AS changed_at
730→    FROM observation
731→    WHERE workspace = $workspace AND updated_at > $since
732→    ORDER BY updated_at DESC LIMIT 20;
733→
734→    LET $recent_suggestions = SELECT "suggestion" AS entity_type, text AS entity_name, status AS change_type, updated_at AS changed_at
735→    FROM suggestion
736→    WHERE workspace = $workspace AND updated_at > $since
737→    ORDER BY updated_at DESC LIMIT 20;
738→
739→    RETURN array::flatten([$recent_decisions, $recent_tasks, $recent_questions, $recent_observations, $recent_suggestions]);
740→  `;
741→
742→  const results = await surreal
743→    .query<[null, null, null, null, null, null, RecentChangeRow[]]>(query, {
744→      project: projectRecord,
745→      workspace: workspaceRecord,
746→      since: sinceDate,
747→    })
748→    .collect<[null, null, null, null, null, null, RecentChangeRow[]]>();
749→
750→  const rows = results[6] ?? [];
751→
752→  return rows.map((r) => ({
753→    entity_type: r.entity_type,
754→    entity_name: r.entity_name,
755→    change_type: r.change_type,
756→    changed_at: toIso(r.changed_at),
757→  }));
758→}
