211→// ---------------------------------------------------------------------------
212→// Recent Changes Injection into System Prompt (04-02: pure)
213→// ---------------------------------------------------------------------------
214→
215→/**
216→ * Injects recent changes XML into a system prompt with correct ordering:
217→ * - <urgent-context> is injected BEFORE <brain-context>
218→ * - <context-update> is injected AFTER <brain-context>
219→ *
220→ * For array-form system prompts, each block becomes a separate text element
221→ * with cache_control: ephemeral.
222→ */
223→export function injectRecentChanges(
224→  system: SystemPrompt,
225→  recentChangesXml: string,
226→): InjectionResult["system"] {
227→  if (!recentChangesXml) return system ?? "";
228→
229→  // Extract urgent-context and context-update blocks from the XML
230→  const urgentMatch = recentChangesXml.match(/<urgent-context>[\s\S]*?<\/urgent-context>/);
231→  const updateMatch = recentChangesXml.match(/<context-update>[\s\S]*?<\/context-update>/);
232→
233→  const urgentBlock = urgentMatch?.[0] ?? "";
234→  const updateBlock = updateMatch?.[0] ?? "";
235→
236→  if (!urgentBlock && !updateBlock) return system ?? "";
237→
238→  if (Array.isArray(system)) {
239→    const result = [...system];
240→
241→    // Find the brain-context block index for insertion ordering
242→    const brainContextIdx = result.findIndex(
243→      (block) => typeof block.text === "string" && block.text.includes("<brain-context>"),
244→    );
245→
246→    if (brainContextIdx >= 0) {
247→      // Insert urgent BEFORE brain-context, update AFTER
248→      if (updateBlock) {
249→        result.splice(brainContextIdx + 1, 0, {
250→          type: "text",
251→          text: updateBlock,
252→          cache_control: { type: "ephemeral" },
253→        });
254→      }
255→      if (urgentBlock) {
256→        result.splice(brainContextIdx, 0, {
257→          type: "text",
258→          text: urgentBlock,
259→          cache_control: { type: "ephemeral" },
260→        });
261→      }
262→    } else {
263→      // No brain-context block -- append both at end (urgent first, then update)
264→      if (urgentBlock) {
265→        result.push({ type: "text", text: urgentBlock, cache_control: { type: "ephemeral" } });
266→      }
267→      if (updateBlock) {
268→        result.push({ type: "text", text: updateBlock, cache_control: { type: "ephemeral" } });
269→      }
270→    }
271→
272→    return result;
273→  }
274→
275→  if (typeof system === "string") {
276→    // String-form: find <brain-context> position for ordering
277→    const brainContextPos = system.indexOf("<brain-context>");
278→
279→    if (brainContextPos >= 0) {
280→      const brainContextEnd = system.indexOf("</brain-context>");
281→      const afterBrainContext = brainContextEnd >= 0
282→        ? brainContextEnd + "</brain-context>".length
283→        : system.length;
284→
285→      const before = system.slice(0, brainContextPos);
286→      const brainSection = system.slice(brainContextPos, afterBrainContext);
287→      const after = system.slice(afterBrainContext);
288→
289→      const parts = [before.trimEnd()];
290→      if (urgentBlock) parts.push(urgentBlock);
291→      parts.push(brainSection);
292→      if (updateBlock) parts.push(updateBlock);
293→      parts.push(after.trimStart());
294→
295→      return parts.filter(Boolean).join("\n\n");
296→    }
297→
298→    // No brain-context -- append both
299→    const parts = [system];
300→    if (urgentBlock) parts.push(urgentBlock);
301→    if (updateBlock) parts.push(updateBlock);
302→    return parts.join("\n\n");
303→  }
304→
305→  // No existing system prompt -- combine blocks
306→  const parts: string[] = [];
307→  if (urgentBlock) parts.push(urgentBlock);
308→  if (updateBlock) parts.push(updateBlock);
309→  return parts.join("\n\n");
310→}
