939→  workspaceRecord: RecordId<"workspace", string>;
940→  entityRecord: GraphEntityRecord;
941→  limit: number;
942→}): Promise<EntityNeighbor[]> {
943→  const [rows] = await input.surreal
944→    .query<[UnifiedEdgeRow[]]>(
