189→/**
190→ * Creates an observation AND triggers the coordinator webhook endpoint.
191→ * In production, the SurrealDB DEFINE EVENT fires the webhook automatically.
192→ * In tests, we simulate this by POSTing to the coordinator endpoint directly.
193→ */
194→export async function createObservationWithCoordinator(
