529→}
530→
531→export class FeedStreamController {
532→  private events: FeedStreamEvent[] = [];
533→  private rawEvents: string[] = [];
534→  private reader: ReadableStreamDefaultReader<Uint8Array> | undefined;
535→  private abortController = new AbortController();
536→  private buffer = "";
537→  private decoder = new TextDecoder();
538→  private connected = false;
539→  private connectionPromise: Promise<void> | undefined;
540→  private lastEventId: string | undefined;
541→
542→  constructor(
543→    private baseUrl: string,
544→    private workspaceId: string,
545→    private user: TestUser,
546→    private options?: { lastEventId?: string },
547→  ) {
548→    this.lastEventId = options?.lastEventId;
549→  }
550→
551→  /** Start listening for SSE events. */
552→  async connect(): Promise<void> {
553→    this.connectionPromise = this._connect();
554→    // Give the connection a moment to establish
555→    await new Promise((resolve) => setTimeout(resolve, 200));
556→  }
557→
558→  /** Get the last event ID received from the server. */
559→  getLastEventId(): string | undefined {
560→    return this.lastEventId;
561→  }
562→
563→  private async _connect(): Promise<void> {
564→    const url = `${this.baseUrl}/api/workspaces/${this.workspaceId}/feed/stream`;
565→    const headers: Record<string, string> = {
566→      Accept: "text/event-stream",
567→      ...this.user.headers,
568→    };
569→    if (this.lastEventId) {
570→      headers["Last-Event-ID"] = this.lastEventId;
571→    }
572→    const response = await fetch(url, {
573→      headers,
574→      signal: this.abortController.signal,
575→    });
576→
577→    if (!response.ok || !response.body) {
578→      throw new Error(`Failed to open feed stream (${response.status})`);
579→    }
580→
581→    this.connected = true;
582→    this.reader = response.body.getReader();
583→
584→    try {
585→      while (true) {
586→        const { value, done } = await this.reader.read();
587→        if (done) break;
588→
589→        this.buffer += this.decoder.decode(value, { stream: true });
590→        const segments = this.buffer.split("\n\n");
591→        this.buffer = segments.pop() ?? "";
592→
593→        for (const segment of segments) {
594→          const lines = segment.split("\n");
595→          const idLine = lines.find((line) => line.startsWith("id: "));
596→          const dataLine = lines.find((line) => line.startsWith("data: "));
597→          if (!dataLine) continue;
598→
599→          // Track the last event ID for reconnection
600→          if (idLine) {
601→            this.lastEventId = idLine.slice("id: ".length).trim();
602→          }
603→
604→          const raw = dataLine.slice("data: ".length);
605→          this.rawEvents.push(raw);
606→
607→          try {
608→            const event = JSON.parse(raw) as FeedStreamEvent;
609→            this.events.push(event);
610→          } catch {
611→            // Non-JSON event (keep-alive comment, etc.)
612→          }
613→        }
614→      }
615→    } catch (e: unknown) {
616→      // AbortError is expected when we close the stream
617→      if (e instanceof DOMException && e.name === "AbortError") return;
618→      if (e instanceof Error && e.message.includes("abort")) return;
619→      throw e;
620→    }
621→  }
