623→  /** Wait for at least N feed_update events, with timeout. */
624→  async waitForEvents(count: number, timeoutMs: number = 5000): Promise<FeedStreamEvent[]> {
625→    const start = Date.now();
626→    while (this.events.length < count && Date.now() - start < timeoutMs) {
627→      await new Promise((resolve) => setTimeout(resolve, 100));
628→    }
629→    return [...this.events];
630→  }
631→
632→  /** Get all collected events so far. */
633→  getEvents(): FeedStreamEvent[] {
634→    return [...this.events];
635→  }
636→
637→  /** Get all raw event strings. */
638→  getRawEvents(): string[] {
639→    return [...this.rawEvents];
640→  }
641→
642→  /** Whether the stream connection was established. */
643→  isConnected(): boolean {
644→    return this.connected;
645→  }
646→
647→  /** Close the SSE connection. */
648→  close(): void {
649→    this.abortController.abort();
650→    this.connected = false;
651→  }
