683→/**
684→ * Creates a deterministic fake embedding vector for testing.
685→ * Uses a seed to produce a reproducible 1536-dimension unit vector.
686→ */
687→export function fakeEmbedding(seed: number): number[] {
688→  const dimension = 1536;
689→  const embedding = new Array<number>(dimension);
690→  let state = seed;
691→  for (let i = 0; i < dimension; i++) {
692→    state = ((state * 1103515245 + 12345) & 0x7fffffff);
693→    embedding[i] = (state / 0x7fffffff) * 2 - 1;
694→  }
695→  const magnitude = Math.sqrt(embedding.reduce((sum, v) => sum + v * v, 0));
696→  for (let i = 0; i < dimension; i++) {
697→    embedding[i] = embedding[i] / magnitude;
698→  }
699→  return embedding;
700→}
