    const brainContextIdx = result.findIndex(
      (block) => typeof block.text === "string" && block.text.includes("<brain-context>"),
    );

    if (brainContextIdx >= 0) {
      // Insert urgent BEFORE brain-context, update AFTER
      if (updateBlock) {
