          type: "text",
          text: updateBlock,
          cache_control: { type: "ephemeral" },
        });
      }
      if (urgentBlock) {
        result.splice(brainContextIdx, 0, {
          type: "text",
          text: urgentBlock,
          cache_control: { type: "ephemeral" },
        });
      }
    } else {
